import{_ as o,o as i,c as l,a6 as a}from"./chunks/framework.CgU7tkAh.js";const m=JSON.parse('{"title":"Locales","description":"","frontmatter":{},"headers":[],"relativePath":"admin/locales/index.md","filePath":"admin/locales/index.md"}'),t={name:"admin/locales/index.md"};function d(s,e,c,n,r,p){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="locales" tabindex="-1">Locales <a class="header-anchor" href="#locales" aria-label="Permalink to “Locales”">​</a></h1><p>Locale is a grouping record to hold a specific list of categories / foods and its inheritance.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><ul><li><p><code>Locale ID</code> - Valid locale ID and unique string within <code>locale</code> records</p></li><li><p><code>Prototype locale ID</code> - Prototype locale it inherits foods data from</p></li><li><p><code>English name</code> - English name of the language (e.g. Czech)</p></li><li><p><code>Local name</code> - Local name of the language (e.g. Čeština)</p></li><li><p><code>Country flag code</code> - Country code to select correct flag (<code>DEPRECATED - moved to language settings</code>)</p></li><li><p><code>Text direction</code> - Read / write direction of text. Valid options are <code>ltr</code> or <code>rlt</code> (<code>DEPRECATED - moved to language settings</code>)</p></li><li><p><code>Food index enabled</code> - Enable food index for this locale</p></li><li><p><code>Food index language backend</code> - Language backend for food index</p></li><li><p><code>Visibility</code> - Record visibility, valid options are <code>public</code> or <code>restricted</code> (<a href="/admin/acl/securables#record-visibility">record visibility</a>).</p></li></ul><h2 id="deletion" tabindex="-1">Deletion <a class="header-anchor" href="#deletion" aria-label="Permalink to “Deletion”">​</a></h2><p>Locale deletion won&#39;t be permitted if there are surveys using it. User firstly needs to update the surveys to use different locale.</p><h2 id="recipe-foods" tabindex="-1">Recipe foods <a class="header-anchor" href="#recipe-foods" aria-label="Permalink to “Recipe foods”">​</a></h2><p>Recipe foods management</p><h2 id="split-lists" tabindex="-1">Split lists <a class="header-anchor" href="#split-lists" aria-label="Permalink to “Split lists”">​</a></h2><p>Split list entries management</p><p>Entry has following fields:</p><ul><li><code>First word</code> - first word</li><li><code>Words</code> - space delimited list of words</li></ul><h2 id="split-words" tabindex="-1">Split words <a class="header-anchor" href="#split-words" aria-label="Permalink to “Split words”">​</a></h2><p>Split words entries management</p><p>Entry has following fields:</p><ul><li><code>Words</code> - space delimited list of words</li></ul><h2 id="synonym-sets" tabindex="-1">Synonym sets <a class="header-anchor" href="#synonym-sets" aria-label="Permalink to “Synonym sets”">​</a></h2><p>Synonym sets entries management</p><p>Entry has following fields:</p><ul><li><code>Synonyms</code> - space delimited list of synonyms</li></ul><h3 id="new-locale-setup" tabindex="-1">New locale setup <a class="header-anchor" href="#new-locale-setup" aria-label="Permalink to “New locale setup”">​</a></h3><ol><li><p>Within the <a href="/admin/locales/"><code>locales</code></a> section, click on the <code>New locale</code> button.</p></li><li><p>Complete all fields and ensure <code>Food index enabled</code> is toggled on. Click <code>save</code> to create the new locale.</p></li><li><p>Go to the <a href="/admin/locales/#tasks"><code>Tasks</code></a> tab.</p></li><li><p>From the drop-down list, select <code>Locale - Copy data</code> job.</p></li><li><p>Under the <code>Job Parameters</code> section, click in the box <code>Source Locale ID</code>, then select the locale you want to clone e.g. United Kingdom (current) and confirm.</p></li><li><p>Leave the <code>Subtasks</code> list as it is (all items ticked), unless you specifically want to exclude some items from the copy process.</p></li><li><p><code>Submit</code> and then <code>Save</code>.</p></li></ol>',22)])])}const f=o(t,[["render",d]]);export{m as __pageData,f as default};
